from __future__ import annotations

import argparse
import collections
import pathlib
import sys
import typing

import yaml

MODEL_REGISTRY_PATH = pathlib.Path("examples/auto_deploy/model_registry/models.yaml")
EXPECTED_MODEL_KEYS = {"name", "yaml_extra"}


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Validate the AutoDeploy model registry for duplicates and entry structure."
    )
    parser.add_argument(
        "--path",
        type=pathlib.Path,
        default=MODEL_REGISTRY_PATH,
        help="Path to the model registry YAML file.",
    )
    return parser.parse_args()


def load_registry(path: pathlib.Path) -> dict[str, typing.Any]:
    try:
        with path.open(encoding="utf-8") as file:
            loaded = yaml.safe_load(file)
    except FileNotFoundError as error:
        raise ValueError(f"Registry file does not exist: {path}") from error
    except yaml.YAMLError as error:
        raise ValueError(f"Failed to parse YAML in {path}: {error}") from error

    if not isinstance(loaded, dict):
        raise ValueError(f"Expected top-level mapping in {path}, got {type(loaded).__name__}.")

    return loaded


def validate_models(models: typing.Any) -> list[str]:
    if not isinstance(models, list):
        return [f"Expected 'models' to be a list, got {type(models).__name__}."]

    errors: list[str] = []
    seen_names: dict[str, list[int]] = collections.defaultdict(list)

    for index, model_entry in enumerate(models, start=1):
        entry_label = f"models[{index}]"
        if not isinstance(model_entry, dict):
            errors.append(
                f"{entry_label}: expected a mapping entry, got {type(model_entry).__name__}."
            )
            continue

        entry_keys = set(model_entry)
        missing_keys = sorted(EXPECTED_MODEL_KEYS - entry_keys)
        unexpected_keys = sorted(entry_keys - EXPECTED_MODEL_KEYS)
        if missing_keys or unexpected_keys:
            details: list[str] = []
            if missing_keys:
                details.append(f"missing keys {missing_keys}")
            if unexpected_keys:
                details.append(f"unexpected keys {unexpected_keys}")
            joined_details = ", ".join(details)
            errors.append(
                f"{entry_label}: expected exactly the keys ['name', 'yaml_extra']; {joined_details}."
            )

        name = model_entry.get("name")
        if not isinstance(name, str) or not name.strip():
            errors.append(f"{entry_label}: missing non-empty string 'name'.")
        yaml_extra = model_entry.get("yaml_extra")
        if not isinstance(yaml_extra, list) or not all(
            isinstance(item, str) and item.strip() for item in yaml_extra
        ):
            errors.append(f"{entry_label}: 'yaml_extra' must be a list of non-empty strings.")

        if not isinstance(name, str) or not name.strip():
            continue

        seen_names[name].append(index)

    for name, indices in sorted(seen_names.items()):
        if len(indices) > 1:
            joined_indices = ", ".join(str(index) for index in indices)
            errors.append(f"Duplicate model name {name!r} found at entries: {joined_indices}.")

    return errors


def main() -> int:
    args = parse_args()

    try:
        registry = load_registry(args.path)
    except ValueError as error:
        print(f"Model registry validation failed: {error}", file=sys.stderr)
        return 1

    errors = validate_models(registry.get("models"))
    if errors:
        print(f"Model registry validation failed for {args.path}:", file=sys.stderr)
        for error in errors:
            print(f" - {error}", file=sys.stderr)
        return 1

    print(f"Model registry validation passed for {args.path}.")
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
# SPDX-FileCopyrightText: Copyright (c) 2026 NVIDIA CORPORATION & AFFILIATES. All rights reserved.
# SPDX-License-Identifier: Apache-2.0

import ast
import pathlib
import sys


class PinnedMemoryUsageChecker(ast.NodeVisitor):
    def __init__(self, *, allow_direct_pin_memory: bool) -> None:
        self.allow_direct_pin_memory = allow_direct_pin_memory
        self.violations: list[tuple[int, str]] = []

    def visit_Call(self, node: ast.Call) -> None:
        if isinstance(node.func, ast.Attribute) and node.func.attr == "pin_memory":
            if not self.allow_direct_pin_memory:
                self.violations.append(
                    (
                        node.lineno,
                        "Use `maybe_pin_memory(tensor)` instead of direct `.pin_memory()`.",
                    )
                )

        for keyword in node.keywords:
            if (
                keyword.arg == "pin_memory"
                and isinstance(keyword.value, ast.Constant)
                and keyword.value.value is True
            ):
                self.violations.append(
                    (
                        node.lineno,
                        "Use `pin_memory=prefer_pinned()` instead of `pin_memory=True`.",
                    )
                )

        self.generic_visit(node)


def _check_file(path: pathlib.Path) -> list[tuple[int, str]]:
    try:
        source = path.read_text(encoding="utf-8")
    except OSError as exc:
        return [(0, f"Failed to read file: {exc}")]

    try:
        tree = ast.parse(source, filename=str(path))
    except SyntaxError as exc:
        return [(exc.lineno or 0, f"Failed to parse file: {exc.msg}")]

    allow_direct_pin_memory = path.as_posix().endswith("tensorrt_llm/_utils.py")
    checker = PinnedMemoryUsageChecker(allow_direct_pin_memory=allow_direct_pin_memory)
    checker.visit(tree)
    return checker.violations


def main(argv: list[str]) -> int:
    if len(argv) <= 1:
        return 0

    has_violations = False
    for file_arg in argv[1:]:
        path = pathlib.Path(file_arg)
        violations = _check_file(path)
        for lineno, message in violations:
            has_violations = True
            print(f"{path}:{lineno}: {message}")

    if has_violations:
        print("\nPinned-memory policy check failed.")
        print("Use `tensorrt_llm._utils.maybe_pin_memory()` for direct pinning.")
        return 1
    return 0


if __name__ == "__main__":
    raise SystemExit(main(sys.argv))

#!/usr/bin/env python3

import re
import sys


def commit_message_has_signoff(message):
    """
    Check if the commit message has a Signed-off-by line.

    Args:
        message (str): The commit message.

    Returns:
        bool: True if the message is valid, False otherwise.
    """
    for line in message.splitlines():
        if re.match(r'^Signed-off-by: .+ <.+>$', line):
            return True
    return False


def main():
    if len(sys.argv) != 2:
        print("Usage: python dco_check.py <commit message filename>")
        sys.exit(1)

    # Read the commit message from the file passed as an argument by Git
    with open(sys.argv[1], 'r') as file:
        message = file.read().strip()

    # Validate the commit message
    if not commit_message_has_signoff(message):
        print(
            "The commit message does not contain a Signed-off-by line. Please review CONTRIBUTING.md for more details."
        )
        sys.exit(1)


if __name__ == "__main__":
    main()

LICENSE_PATTERNS = {"license*", "licence*", "copying*", "notice*"}
COPYRIGHT_PATTERNS = {"authors*", "contributors*", "copyright*"}
NOTICE_ATTRIBUTION_PATTERNS = {
    "notice*",
}

import os
import re
import subprocess
from abc import ABC, abstractmethod
from fnmatch import fnmatch
from importlib.metadata import PackageNotFoundError
from importlib.metadata import version as get_package_version
from typing import Any, Dict, List, Optional, Set, Tuple

from _constants import LICENSE_PATTERNS, NOTICE_ATTRIBUTION_PATTERNS


def _find_matching_files(directory: str, patterns: Set[str]) -> List[str]:
    """Find files in directory matching patterns (case-insensitive, non-recursive)."""
    if not os.path.isdir(directory):
        return []
    return sorted(
        os.path.join(directory, f)
        for f in os.listdir(directory)
        if os.path.isfile(os.path.join(directory, f))
        and any(fnmatch(f.lower(), p) for p in patterns)
    )


def _normalize_package_name(package: str) -> str:
    """Normalize package names for consistent dependency tracking."""
    cuda_related = (
        "cuda",
        "cublas",
        "curand",
        "cusolver",
        "cusparse",
        "cufft",
        "nvjitlink",
        "nvptxcompiler",
        "culibos",
    )

    # Remove CUDA version suffixes (e.g., cuda-cccl-12-9 → cuda-cccl, nvptxcompiler-13-1 → nvptxcompiler)
    match = re.match(r"^(.+?)-(\d+)-(\d+)$", package)
    if match and any(x in match.group(1) for x in cuda_related):
        package = match.group(1)

    # Strip other common suffixes and prefixes
    for suffix in ("-devel", "-dev"):
        if package.endswith(suffix):
            package = package[: -len(suffix)]
            break
    if package.startswith("lib"):
        package = package[3:]

    # CUDA-related packages -> cuda
    if package.startswith("cuda-") or package in cuda_related:
        return "cuda"
    elif package.startswith("glibc-"):
        return "glibc"
    elif package in {"kernel-headers", "linux-headers", "linux-libc"}:
        return "linux"
    elif package in {"ibverbs"}:
        return "rdma-core"
    elif package in {"zmq3"}:
        return "zeromq"
    elif package.startswith("gcc-toolset-"):
        return "gcc"

    # Ubuntu-specific: versioned GCC packages (gcc-13, g++-13, libgcc-13) -> gcc
    elif re.match(r"^(gcc|g\+\+)-(\d+)$", package):
        return "gcc"

    # Ubuntu-specific: versioned Python packages (python3.12, python3.10) -> python
    elif re.match(r"^python(\d+\.\d+)$", package):
        return "cpython"

    # Ubuntu-specific: libstdc++ -> stdc++-N -> gcc
    elif re.match(r"^stdc\+\+(-\d+)?$", package):
        return "gcc"

    # Ubuntu-specific: libc6 becomes c6 after stripping lib prefix -> glibc
    elif re.match(r"^c\d+$", package):
        return "glibc"

    return package


def _normalize_version(package: str, version: str) -> str:
    """Normalize version strings for specific packages."""
    # CUDA: shorten to first two parts (e.g., 13.1.80-1 → 13.1)
    if package == "cuda" and version:
        match = re.match(r"^(\d+\.\d+)", version)
        if match:
            return match.group(1)
    return version


def _normalize_package(raw_package: str, version: str) -> Tuple[str, str, str]:
    """Normalize the name and version strings for specific packages."""
    normalized_pkg = _normalize_package_name(raw_package)
    return normalized_pkg, _normalize_version(normalized_pkg, version), raw_package


class Resolver(ABC):
    """Base class for dependency resolvers."""

    def __init__(self):
        self._cache: Dict[str, Any] = {}

    @abstractmethod
    def get_package(self, file_path: str) -> Optional[Tuple[str, str, str]]:
        """Return (dependency_name, version, raw_package) or None."""

    def get_license_path(self, key: str) -> str:
        """Return license path(s) for a package/file. Override in subclasses."""
        return ""


class DpkgResolver(Resolver):
    """Resolves files using dpkg-query (Debian/Ubuntu)."""

    # Patterns that indicate a file is NOT from a dpkg-managed package
    # These files should be skipped to avoid expensive dpkg-query calls
    SKIP_PATTERNS = (
        "/_deps/",  # CMake FetchContent dependencies
        "/site-packages/",  # Python packages
        "/dist-packages/",  # Python packages (system)
        "/3rdparty/",  # Vendored third-party code
        "/third_party/",  # Vendored third-party code
        "/external/",  # External dependencies
        "/build/",  # Build artifacts (within project)
        "/opt/",  # Optional packages (usually not dpkg-managed)
    )

    def __init__(self):
        super().__init__()
        # Track which packages we've already cached all files for
        self._cached_packages: Set[str] = set()
        # Negative cache: directories known to NOT contain dpkg-managed files
        self._non_dpkg_dirs: Set[str] = set()

    def _cache_all_package_files(self, raw_package: str, result: Tuple[str, str, str]) -> None:
        """Cache all files belonging to a package for fast future lookups."""
        if raw_package in self._cached_packages:
            return

        try:
            # Get all files belonging to this package
            proc = subprocess.run(
                ["dpkg-query", "-L", raw_package],
                capture_output=True,
                text=True,
                timeout=10,
            )
            if proc.returncode == 0:
                for line in proc.stdout.strip().split("\n"):
                    file_path = line.strip()
                    if file_path and file_path not in self._cache:
                        self._cache[file_path] = result
                self._cached_packages.add(raw_package)
        except (subprocess.TimeoutExpired, FileNotFoundError, Exception):
            pass

    def get_package(self, file_path: str) -> Optional[Tuple[str, str, str]]:
        if file_path in self._cache:
            return self._cache[file_path]

        # Skip files that are clearly not from system packages
        # This avoids expensive dpkg-query subprocess calls
        if any(pattern in file_path for pattern in self.SKIP_PATTERNS):
            self._cache[file_path] = None
            return None

        # Check negative directory cache - if we know this directory has no dpkg files
        dir_path = os.path.dirname(file_path)
        if dir_path in self._non_dpkg_dirs:
            self._cache[file_path] = None
            return None

        result = None
        try:
            proc = subprocess.run(
                ["dpkg-query", "-S", file_path], capture_output=True, text=True, timeout=5
            )
            if proc.returncode == 0 and ":" in proc.stdout:
                raw_package = proc.stdout.split(":", 1)[0].split(":")[0]
                version = ""
                ver_proc = subprocess.run(
                    ["dpkg-query", "-W", "-f=${Version}", raw_package],
                    capture_output=True,
                    text=True,
                    timeout=5,
                )
                if ver_proc.returncode == 0:
                    version = ver_proc.stdout.strip()
                result = _normalize_package(raw_package, version)
                # Cache ALL files belonging to this package for fast future lookups
                self._cache_all_package_files(raw_package, result)
            else:
                # File not found in any dpkg package - cache the directory as non-dpkg
                self._non_dpkg_dirs.add(dir_path)
        except (subprocess.TimeoutExpired, FileNotFoundError, Exception):
            pass

        self._cache[file_path] = result
        return result

    # Package-specific license preambles (e.g., for dual-licensed packages)
    LICENSE_PREAMBLES: Dict[str, str] = {
        "libibverbs-dev": (
            "NVIDIA actively chooses the OpenIB.org BSD (MIT variant) license "
            "to apply to files with this copyright and license.\n\n"
        ),
    }

    def get_license_path(self, raw_package: str) -> str:
        cache_key = f"license:{raw_package}"
        if cache_key in self._cache:
            return self._cache[cache_key]

        result = ""
        copyright_path = f"/usr/share/doc/{raw_package}/copyright"
        if os.path.exists(copyright_path):
            try:
                with open(copyright_path, "r", encoding="utf-8", errors="replace") as f:
                    content = f.read()
                refs = set(re.findall(r"/usr/share/common-licenses/([A-Za-z0-9._-]+)", content))
                if refs:
                    combined = f"/tmp/dpkg_license_{raw_package}.txt"
                    with open(combined, "w", encoding="utf-8") as out:
                        # Add package-specific preamble if defined
                        if raw_package in self.LICENSE_PREAMBLES:
                            out.write(self.LICENSE_PREAMBLES[raw_package])
                        out.write(content)
                        for name in sorted(refs):
                            # Strip trailing punctuation (e.g., "LGPL." -> "LGPL")
                            name = name.rstrip(".,;:!?")
                            path = f"/usr/share/common-licenses/{name}"
                            # Resolve symlinks (e.g., GPL -> GPL-3)
                            resolved_path = os.path.realpath(path)
                            if os.path.isfile(resolved_path):
                                out.write(f"\n\n{'=' * 60}\nContents of {path}:\n{'=' * 60}\n\n")
                                with open(
                                    resolved_path, "r", encoding="utf-8", errors="replace"
                                ) as lf:
                                    out.write(lf.read())
                    result = combined
                else:
                    result = copyright_path
            except (IOError, OSError):
                pass

        self._cache[cache_key] = result
        return result


class RpmResolver(Resolver):
    """Resolves files using rpm (RHEL/CentOS)."""

    def get_package(self, file_path: str) -> Optional[Tuple[str, str, str]]:
        if file_path in self._cache:
            return self._cache[file_path]

        result = None
        if os.path.isabs(file_path) and os.path.exists(file_path):
            try:
                proc = subprocess.run(
                    ["rpm", "-qf", "--qf", "%{NAME}\t%{VERSION}-%{RELEASE}", file_path],
                    capture_output=True,
                    text=True,
                    timeout=5,
                )
                if proc.returncode == 0:
                    parts = proc.stdout.strip().split("\t")
                    if len(parts) >= 2:
                        result = _normalize_package(parts[0], parts[1])
            except (subprocess.TimeoutExpired, FileNotFoundError, Exception):
                pass

        self._cache[file_path] = result
        return result

    def get_license_path(self, raw_package: str) -> str:
        cache_key = f"license:{raw_package}"
        if cache_key in self._cache:
            return self._cache[cache_key]

        packages = [raw_package]
        for suffix in ("-devel", "-dev"):
            if raw_package.endswith(suffix):
                packages.append(raw_package[: -len(suffix)])
                break

        paths = []
        for pkg in packages:
            for base in [f"/usr/share/licenses/{pkg}", f"/usr/share/doc/{pkg}"]:
                paths.extend(_find_matching_files(base, LICENSE_PATTERNS))

        result = " OR ".join(sorted(set(paths)))
        self._cache[cache_key] = result
        return result


class PythonPackageResolver(Resolver):
    """Resolves files in Python site-packages/dist-packages."""

    # Packages where NOTICE files should go to attribution instead of license
    NOTICE_TO_ATTRIBUTION = {"torch"}
    PATTERNS = [re.compile(r"/(site|dist)-packages/([^/]+)/")]

    def get_package(self, file_path: str) -> Optional[Tuple[str, str, str]]:
        if file_path in self._cache:
            return self._cache[file_path]

        result = None
        for pattern in self.PATTERNS:
            match = pattern.search(file_path)
            if match:
                pkg = re.sub(r"[-.].*\.(dist-info|egg-info)$", "", match.group(2))
                version = ""
                for name in [pkg.replace("_", "-"), pkg]:
                    try:
                        version = get_package_version(name)
                        break
                    except PackageNotFoundError:
                        pass
                result = (pkg, version, pkg)
                break

        self._cache[file_path] = result
        return result

    def _get_all_license_files(self, file_path: str, license_patterns: Set[str]) -> List[str]:
        """Get all license-related files for a Python package."""
        paths = []
        for pattern in self.PATTERNS:
            match = pattern.search(file_path)
            if match:
                pkg_name = match.group(2)
                base_path = file_path[: match.end() - 1]
                site_dir = file_path[: file_path.find("/", match.start() + 1)]

                paths.extend(_find_matching_files(base_path, license_patterns))

                if os.path.isdir(site_dir):
                    for entry in os.listdir(site_dir):
                        if entry.endswith(".dist-info") and any(
                            entry.startswith(f"{n}-")
                            for n in [
                                pkg_name,
                                pkg_name.replace("-", "_"),
                                pkg_name.replace("_", "-"),
                            ]
                        ):
                            dist_path = os.path.join(site_dir, entry)
                            lic_dir = os.path.join(dist_path, "licenses")
                            if os.path.isdir(lic_dir):
                                paths.extend(_find_matching_files(lic_dir, license_patterns))
                            paths.extend(_find_matching_files(dist_path, license_patterns))
                            break
                break
        return paths

    def get_license_path(self, file_path: str, dependency: str = "") -> str:
        patterns = LICENSE_PATTERNS
        # For specific packages, exclude NOTICE files from license (they go to attribution)
        if dependency in self.NOTICE_TO_ATTRIBUTION:
            patterns = patterns - NOTICE_ATTRIBUTION_PATTERNS
        paths = self._get_all_license_files(file_path, patterns)
        return " OR ".join(paths)

    def get_attribution_path(self, file_path: str, dependency: str = "") -> str:
        """Get attribution files (e.g., NOTICE) for packages that need them separate."""
        if dependency not in self.NOTICE_TO_ATTRIBUTION:
            return ""
        paths = self._get_all_license_files(file_path, NOTICE_ATTRIBUTION_PATTERNS)
        return " OR ".join(paths)

import json
import os
import re
import subprocess
import sys
from dataclasses import asdict, dataclass
from fnmatch import fnmatch
from pathlib import Path
from typing import Any, Dict, Optional, Set

import yaml
from _constants import COPYRIGHT_PATTERNS, LICENSE_PATTERNS
from _package_resolvers import _find_matching_files

try:
    from jsonschema import ValidationError, validate

    JSONSCHEMA_AVAILABLE = True
except ImportError:
    JSONSCHEMA_AVAILABLE = False
    ValidationError = Exception  # type: ignore


VENDOR_MARKERS = [
    "3rdparty/",
    "third-party/",
    "thirdparty/",
    "third_party/",
    "external/",
    "externals/",
    "vendor/",
    "vendored/",
    "deps/",
    "ext/",
]
# _deps is not in VENDOR_MARKERS because it would interfere with vendor
# inference in match(). It is checked separately in has_unknown_vendor().


@dataclass
class DependencyMapping:
    """Maps a file to a dependency."""

    file_path: str
    dependency: str
    version: str = ""
    confidence: str = "high"
    strategy: str = ""
    raw_package: str = ""

    def to_dict(self) -> Dict[str, Any]:
        return asdict(self)


class PatternMatcher:
    """Resolves files using YAML patterns and FetchContent data."""

    def __init__(self, metadata_dir: Path, fetch_content_json: Optional[Path] = None):
        self.patterns: Dict[str, str] = {}  # basename/flag -> dependency
        self.path_aliases: Dict[str, str] = {}  # path pattern -> dependency
        self.absolute_roots: Dict[
            str, str
        ] = {}  # dependency -> absolute path (from absolute directory_matches)
        self.known_names: Set[str] = set()
        self.fetch_content: Dict[str, Dict[str, Any]] = {}
        self._version_cache: Dict[str, str] = {}
        self._warnings: Set[str] = set()

        if (metadata_dir / "_schema.yml").exists() and JSONSCHEMA_AVAILABLE:
            with open(metadata_dir / "_schema.yml") as f:
                self._schema = yaml.safe_load(f)
        else:
            self._schema = None

        self._load_yaml(metadata_dir)
        self._load_fetch_content(
            fetch_content_json or Path(__file__).parents[3] / "3rdparty/fetch_content.json"
        )
        self._add_project_root_pattern()

    def _load_yaml(self, metadata_dir: Path):
        for yaml_file in sorted(metadata_dir.glob("*.yml")):
            if yaml_file.name.startswith("_"):
                continue
            try:
                with open(yaml_file) as f:
                    data = yaml.safe_load(f)
                deps = data.get("dependencies", [data] if "name" in data else [])
                for dep in deps:
                    self._add_dependency(dep, yaml_file)
            except Exception as e:
                print(f"Warning: Error loading {yaml_file.name}: {e}", file=sys.stderr)

    def _add_dependency(self, dep: Dict, source: Path):
        if self._schema and JSONSCHEMA_AVAILABLE:
            try:
                validate(instance=dep, schema=self._schema)
            except ValidationError as e:
                print(f"Warning: Validation error in {source.name}: {e.message}", file=sys.stderr)

        name = dep.get("name")
        if not name:
            return

        for key in dep.get("basename_matches", []):
            if key in self.patterns and key not in self._warnings:
                print(f"Warning: Duplicate pattern '{key}' in {source.name}", file=sys.stderr)
                self._warnings.add(key)
            self.patterns[key] = name

        for comp in dep.get("directory_matches", []):
            if comp in self.path_aliases and comp not in self._warnings:
                print(f"Warning: Duplicate path '{comp}' in {source.name}", file=sys.stderr)
                self._warnings.add(comp)
            self.path_aliases[comp] = name
            self.known_names.add(comp.lower())
            # Absolute paths are used directly as source roots
            if comp.startswith("/"):
                self.absolute_roots[name] = comp

        self.known_names.add(name.lower())

    def _load_fetch_content(self, path: Path):
        try:
            with open(path) as f:
                data = json.load(f)
            for dep in data.get("dependencies", []):
                name = dep.get("name")
                if not name:
                    continue
                display = dep.get("display_name", name)
                self.path_aliases[f"_deps/{name}-src"] = display
                self.known_names.update(
                    [
                        display.lower(),
                        f"{name}-src".lower(),
                        f"{name}-build".lower(),
                        f"{name}-subbuild".lower(),
                    ]
                )
                self.fetch_content[display] = dep
        except Exception as e:
            print(f"Warning: Error loading fetch_content.json: {e}", file=sys.stderr)

    def _add_project_root_pattern(self):
        """Add the project root directory as a path alias for tensorrt-llm.

        This automatically maps files under the project directory to tensorrt-llm,
        which is in IGNORED_DEPS and will be filtered from attribution output.
        """
        # Get project root (4 levels up: scan -> attribution -> scripts -> root)
        project_root = Path(__file__).resolve().parents[3]
        root_name = project_root.name
        self.path_aliases[f"{root_name}/cpp"] = "tensorrt-llm"
        self.known_names.add(root_name.lower())

    def match(self, file_path: str) -> Optional[DependencyMapping]:
        """Match file to dependency using patterns, path aliases, or library inference."""
        basename = os.path.basename(file_path)

        # Exact pattern match
        for key in [basename, file_path]:
            if key in self.patterns:
                dep = self.patterns[key]
                return DependencyMapping(
                    file_path=file_path,
                    dependency=dep,
                    version=self._get_version(dep, file_path),
                    strategy="pattern_match",
                )

        # Path alias match (rightmost wins), including vendor inference
        parts = [p for p in file_path.split("/") if p]
        best_match, best_pos = None, -1

        for pattern, dep in self.path_aliases.items():
            pattern_parts = pattern.strip("/").split("/")
            for i in range(len(parts) - len(pattern_parts) + 1):
                if all(fnmatch(parts[i + j], pp) for j, pp in enumerate(pattern_parts)):
                    if i > best_pos:
                        best_pos = i
                        best_match = DependencyMapping(
                            file_path=file_path,
                            dependency=dep,
                            version=self._get_version(dep, file_path),
                            confidence="medium",
                            strategy="path_alias",
                        )

        # Vendor inference: check if any vendor marker appears deeper than best match
        # e.g., "deepgemm-src/third-party/cutlass/..." -> infer "cutlass"
        vendor_markers_no_slash = [m.rstrip("/") for m in VENDOR_MARKERS]
        for i, part in enumerate(parts):
            if part.lower() in vendor_markers_no_slash and i + 1 < len(parts):
                if i > best_pos:
                    inferred_dep = parts[i + 1]
                    if inferred_dep and not inferred_dep.startswith("."):
                        best_pos = i
                        best_match = DependencyMapping(
                            file_path=file_path,
                            dependency=inferred_dep,
                            version=self._get_git_version(file_path),
                            confidence="medium",
                            strategy="vendor_inference",
                        )

        if best_match:
            return best_match

        # Generic library inference (only for third-party libraries)
        lib_match = re.match(r"^lib([a-zA-Z0-9_-]+)\.(?:so|a)(?:\.\d+)*$", basename)
        if lib_match:
            return DependencyMapping(
                file_path=file_path,
                dependency=lib_match.group(1),
                confidence="low",
                strategy="library_inference",
            )

        return None

    def _get_version(self, dep: str, file_path: str) -> str:
        # FetchContent version
        if dep in self.fetch_content:
            return self.fetch_content[dep].get("git_tag", "")

        # Git submodule version
        if "/_deps/" in file_path:
            version = self._get_git_version(file_path)
            if version:
                return version

        # Special cases
        return self._get_special_version(dep, file_path)

    def _get_git_version(self, file_path: str) -> str:
        """Get version from git submodule."""
        current = os.path.dirname(file_path)
        while current and "/_deps/" in current:
            if current in self._version_cache:
                return self._version_cache[current]
            if os.path.isfile(os.path.join(current, ".git")):
                try:
                    result = subprocess.run(
                        ["git", "describe", "--tags", "--always"],
                        cwd=current,
                        capture_output=True,
                        text=True,
                        timeout=5,
                    )
                    version = result.stdout.strip() if result.returncode == 0 else ""
                    self._version_cache[current] = version
                    return version
                except Exception:
                    self._version_cache[current] = ""
            current = os.path.dirname(current)
        return ""

    def _get_special_version(self, dep: str, file_path: str) -> str:
        """Extract version for special dependencies from header files."""
        cache_key = f"special:{dep}"
        if cache_key in self._version_cache:
            return self._version_cache[cache_key]

        version = ""
        configs = {
            "cpython": (r"/opt/python/(\d+\.\d+\.\d+)/", None, None),
            "tensorrt-llm": "any",
            "tensorrt": (
                r"(.*/tensorrt/include)/",
                "NvInferVersion.h",
                [(r"TRT_(\w+)_ENTERPRISE\s+(\d+)", ["MAJOR", "MINOR", "PATCH"])],
            ),
            "cuda": (
                r"(.*/cuda[^/]*/(?:targets/[^/]+/)?include)/",
                "cuda_runtime_api.h",
                [
                    (
                        r"CUDART_VERSION\s+(\d+)",
                        lambda m: f"{int(m.group(1)) // 1000}.{(int(m.group(1)) % 1000) // 10}",
                    )
                ],
            ),
            "ucx": (
                r"(.*/ucx/include)/",
                "ucp/api/ucp_version.h",
                [(r"UCP_API_(\w+)\s+(\d+)", ["MAJOR", "MINOR"])],
            ),
            "nixl": (
                r"(/opt/nvidia/nvda_nixl)/",
                "VERSION",
                [(r"(\S+)", lambda m: m.group(1))],
            ),
            "openmpi": (
                r"(/opt/hpcx)/",
                "VERSION",
                # Extract HPC-X version (e.g., "HPC-X v2.25.1" -> "hpcx-2.25.1")
                [(r"HPC-X v(\S+)", lambda m: f"hpcx-{m.group(1)}")],
            ),
            "nvshmem": (
                r"(.*/nvshmem-build)/",
                "NVSHMEMVersion.cmake",
                # Extract version from set(PACKAGE_VERSION "3.2.5.1")
                [(r'set\(PACKAGE_VERSION "([^"]+)"\)', lambda m: m.group(1))],
            ),
            "mooncake": (
                r"(/usr/local/Mooncake)/",
                "VERSION",
                [(r"(\S+)", lambda m: m.group(1))],
            ),
        }

        if dep not in configs:
            # Vendored dep - use parent version
            match = re.search(r"/_deps/([^/]+)-src/", file_path)
            if match:
                parent = match.group(1)
                if parent in self.fetch_content:
                    version = self.fetch_content[parent].get("git_tag", "")
            self._version_cache[cache_key] = version
            return version

        if isinstance(configs[dep], str):
            version = configs[dep]
            self._version_cache[cache_key] = version
            return version

        dir_pattern, header, extractors = configs[dep]

        if dir_pattern:
            path_match = re.search(dir_pattern, file_path)
            if path_match:
                if header is None:
                    # Version is in the path capture group (e.g., cpython)
                    version = path_match.group(1)
                elif extractors:
                    header_path = os.path.join(path_match.group(1), header)
                    if os.path.isfile(header_path):
                        try:
                            with open(header_path) as f:
                                content = f.read()
                            for pattern, processor in extractors:
                                if callable(processor):
                                    m = re.search(pattern, content)
                                    if m:
                                        version = processor(m)
                                else:
                                    vals = {}
                                    for m in re.finditer(pattern, content):
                                        vals[m.group(1)] = m.group(2)
                                    if all(k in vals for k in processor):
                                        version = ".".join(vals[k] for k in processor)
                        except Exception:
                            pass

        self._version_cache[cache_key] = version
        return version

    def has_unknown_vendor(self, file_path: str) -> bool:
        """Check if file is in an unknown vendor or FetchContent directory."""
        path_lower = file_path.lower()
        for marker in [*VENDOR_MARKERS, "_deps/"]:
            idx = 0
            while (idx := path_lower.find(marker, idx)) != -1:
                start = idx + len(marker)
                end = path_lower.find("/", start)
                component = path_lower[start : end if end != -1 else None]
                if component and component not in self.known_names:
                    return True
                idx = end if end != -1 else len(path_lower)
        return False

    def get_source_root(self, file_path: str, dependency: str = "") -> Optional[Path]:
        """Get source root for file (handles vendored deps).

        Supports multiple build system patterns:
        - FetchContent: /_deps/<name>-src/
        - ExternalProject: /<name>-build/ (e.g., nvshmem-build)
        - Container install paths via install_path in YAML metadata
        """
        # Check if dependency has an absolute path in directory_matches
        if dependency and dependency in self.absolute_roots:
            return Path(self.absolute_roots[dependency])

        # Try FetchContent pattern first: /_deps/<name>-src/
        match = re.search(r"/_deps/([^/]+)-src/", file_path)
        if match:
            root = Path(file_path[: match.end() - 1])
            remainder = file_path[match.end() :]
        else:
            # Try ExternalProject pattern: /<name>-build/
            match = re.search(r"/([^/]+-build)/", file_path)
            if match:
                root = Path(file_path[: match.end() - 1])
                remainder = file_path[match.end() :]
            else:
                return None

        remainder_lower = remainder.lower()

        # Check path_aliases that represent subdirectories (e.g., csrc/cutlass)
        # These take priority over generic vendor markers
        for pattern in self.path_aliases:
            if pattern.startswith("_deps/"):
                continue  # Skip FetchContent patterns
            pattern_lower = pattern.lower().rstrip("/")
            idx = remainder_lower.find(pattern_lower)
            if idx != -1:
                end_idx = idx + len(pattern_lower)
                # Ensure it's a directory boundary match
                if end_idx == len(remainder_lower) or remainder[end_idx] == "/":
                    vendor_root = root / remainder[:end_idx]
                    if vendor_root.is_dir():
                        return vendor_root

        # Check standard vendor markers
        for marker in VENDOR_MARKERS:
            idx = remainder_lower.find(marker.rstrip("/") + "/")
            if idx != -1:
                vendor_start = idx + len(marker)
                next_slash = remainder_lower.find("/", vendor_start)
                vendor_path = remainder[: next_slash if next_slash != -1 else len(remainder)]
                vendor_root = root / vendor_path
                if vendor_root.is_dir():
                    return vendor_root

        return root if root.is_dir() else None

    def get_license_path(self, file_path: str, dependency: str = "") -> str:
        root = self.get_source_root(file_path, dependency)
        return " OR ".join(_find_matching_files(str(root), LICENSE_PATTERNS)) if root else ""

    def get_copyright_files(self, file_path: str) -> str:
        root = self.get_source_root(file_path)
        return " OR ".join(_find_matching_files(str(root), COPYRIGHT_PATTERNS)) if root else ""

    def get_source_url(self, dep: str, version: str = "") -> str:
        data = self.fetch_content.get(dep, {})
        repo, tag = data.get("git_repository", ""), data.get("git_tag", "")
        if not repo or not tag:
            return ""
        # Only return URL if version matches (or no version specified)
        if version and tag != version:
            return ""
        repo = repo.replace("${github_base_url}", "https://github.com").rstrip(".git")
        return f"{repo}/tree/{tag}"

