          "description": "The list of levels associated with the standard. Some standards have different levels of compliance.",
          "items": {
            "type": "object",
            "title": "Level",
            "additionalProperties": false,
            "properties": {
              "bom-ref": {
                "$ref": "#/definitions/refType",
                "title": "BOM Reference",
