              },
              "identifier": {
                "type": "string",
                "title": "Identifier",
                "description": "The identifier used in the standard to identify a specific level."
              },
              "title": {
                "type": "string",
                "title": "Title",
                "description": "The title of the level."
              },
              "description": {
                "type": "string",
                "title": "Description",
