# =============================================================================
# open_search_db.py
#
# This module provides a client class for interacting with an OpenSearch database
# used for CI/CD job and test result monitoring. It defines various project index
# names, environment variable settings for the OpenSearch connection, and constants
# for queries and timeouts.
#
# The primary interface is the `OpenSearchDB` class, which provides functionality for
# querying and processing indexed test/job metadata within NVIDIA's CI infrastructure,
# such as job information, stage results, test status, and related analytics for display
# or automation.
#
# Typical usage requires setting environment variables for authentication and server
# address, as used by Jenkins or related services.
#
# =============================================================================

import hashlib
import json
import logging
import os
import time

import requests
from requests.auth import HTTPProxyAuth

PROJECT_ROOT = "swdl-trtllm-infra"
MODE = "prod"
VERSION = "v1"

# CI monitor indexes, now only support read access.
JOB_PROJECT_NAME = f"{PROJECT_ROOT}-ci-{MODE}-job_info"
STAGE_PROJECT_NAME = f"{PROJECT_ROOT}-ci-{MODE}-stage_info"
TEST_PROJECT_NAME = f"{PROJECT_ROOT}-ci-{MODE}-test_info"
JOB_MACHINE_PROJECT_NAME = f"{PROJECT_ROOT}-ci-{MODE}-job_machine_info"
FAILED_STEP_PROJECT_NAME = f"{PROJECT_ROOT}-ci-{MODE}-failed_step_info"
PR_PROJECT_NAME = f"{PROJECT_ROOT}-ci-{MODE}-pr_info"
PERF_SANITY_PROJECT_NAME = f"{PROJECT_ROOT}-ci-{MODE}-perf_sanity_info"

READ_ACCESS_PROJECT_NAME = [
    JOB_PROJECT_NAME,
    STAGE_PROJECT_NAME,
    TEST_PROJECT_NAME,
    JOB_MACHINE_PROJECT_NAME,
    FAILED_STEP_PROJECT_NAME,
    PR_PROJECT_NAME,
    PERF_SANITY_PROJECT_NAME,
]

WRITE_ACCESS_PROJECT_NAME = [
    PERF_SANITY_PROJECT_NAME,
]

DISABLE_OPEN_SEARCH_DB_FOR_LOCAL_TEST = False

DEFAULT_QUERY_SIZE = 3000
DEFAULT_RETRY_COUNT = 5
DEFAULT_LOOKBACK_DAYS = 7
POST_TIMEOUT_SECONDS = 20
QUERY_TIMEOUT_SECONDS = 10

OPEN_SEARCH_DB_BASE_URL = os.getenv("OPEN_SEARCH_DB_BASE_URL", "")
OPEN_SEARCH_DB_USERNAME = os.getenv("OPEN_SEARCH_DB_CREDENTIALS_USR", "")
OPEN_SEARCH_DB_PASSWORD = os.getenv("OPEN_SEARCH_DB_CREDENTIALS_PSW", "")


class OpenSearchDB:
    logger = logging.getLogger(__name__)
    query_build_id_cache: dict = {}

    def __init__(self) -> None:
        pass

    @staticmethod
    def typeCheckForOpenSearchDB(json_data) -> bool:
        """
        Check if the data is valid for OpenSearchDB.

        :param json_data: Data to check, type dict or list.
        :return: bool, True if data is valid, False otherwise.
        """
        if isinstance(json_data, list):
            return all(
                OpenSearchDB.typeCheckForOpenSearchDB(item)
                for item in json_data)
        if not isinstance(json_data, dict):
            OpenSearchDB.logger.info(
                f"OpenSearchDB type check failed! Expected dict, got {type(json_data).__name__}"
            )
            return False

        allowed_keys = {
            "@timestamp", "_id", "_index", "_score", "_type", "_project",
            "_shard", "_version"
        }
        type_map = {
            "l_": int,
            "d_": float,
            "s_": str,
            "b_": bool,
            "ts_": int,
            "flat_": dict,
            "ni_": (str, int, float),
        }

        for key, value in json_data.items():
            matched = False
            for prefix, expected_type in type_map.items():
                if key.startswith(prefix):
                    if not isinstance(value, expected_type):
                        OpenSearchDB.logger.info(
                            f"OpenSearchDB type check failed! key:{key}, value:{value} value_type:{type(value)}"
                        )
                        return False
                    matched = True
                    break
            if not matched:
                if key not in allowed_keys:
                    OpenSearchDB.logger.info(
                        f"Unknown key type! key:{key}, value_type:{type(value)}"
                    )
                    return False
        return True

    @staticmethod
    def _calculate_timestamp(days_ago) -> int:
        """
        Calculate timestamp in milliseconds.

        :param days_ago: Number of days ago.
        :return: Timestamp in milliseconds.
        """
        return int(time.time() -
                   24 * 3600 * days_ago) // (24 * 3600) * 24 * 3600 * 1000

    @staticmethod
    def add_id_of_json(data) -> None:
        """
        Add _id field to the data.

        :param data: Data to add _id field, type dict or list.
        :return: None.
        """
        if isinstance(data, list):
            for d in data:
                OpenSearchDB.add_id_of_json(d)
            return
        if not isinstance(data, dict):
            raise TypeError("data is not a dict, type:{}".format(type(data)))
        data_str = json.dumps(data, sort_keys=True, indent=2).encode("utf-8")
        data["_id"] = hashlib.md5(data_str).hexdigest()

    @staticmethod
    def postToOpenSearchDB(json_data, project) -> bool:
        """
        Post data to OpenSearchDB.

        :param json_data: Data to post, type dict or list.
        :param project: Name of the project.
        :return: bool, True if post successful, False otherwise.
        """
        use_poc_db = "sandbox" in project
        if not OPEN_SEARCH_DB_BASE_URL:
            OpenSearchDB.logger.info("OPEN_SEARCH_DB_BASE_URL is not set")
            return False
        if not use_poc_db and (not OPEN_SEARCH_DB_USERNAME
                               or not OPEN_SEARCH_DB_PASSWORD):
            OpenSearchDB.logger.info(
                "OPEN_SEARCH_DB_USERNAME or OPEN_SEARCH_DB_PASSWORD is not set")
            return False
        if not use_poc_db and project not in WRITE_ACCESS_PROJECT_NAME:
            OpenSearchDB.logger.info(
                f"project {project} is not in write access project list: {json.dumps(WRITE_ACCESS_PROJECT_NAME)}"
            )
            return False
        if not OpenSearchDB.typeCheckForOpenSearchDB(json_data):
            OpenSearchDB.logger.info(
                f"OpenSearchDB type check failed! json_data:{json_data}")
            return False

        json_data_dump = json.dumps(json_data)

        if DISABLE_OPEN_SEARCH_DB_FOR_LOCAL_TEST:
            OpenSearchDB.logger.info(
                f"OpenSearchDB is disabled for local test, skip posting to OpenSearchDB: {json_data_dump}"
            )
            return True

        url = f"{OPEN_SEARCH_DB_BASE_URL}/dataflow2/{project}/posting"
        headers = {
            "Content-Type": "application/json",
            "Accept-Charset": "UTF-8"
        }

        for attempt in range(DEFAULT_RETRY_COUNT):
            try:
                args = {
                    "url": url,
                    "data": json_data_dump,
                    "headers": headers,
                    "timeout": POST_TIMEOUT_SECONDS,
                }
                if not use_poc_db:
                    args["auth"] = HTTPProxyAuth(OPEN_SEARCH_DB_USERNAME,
                                                 OPEN_SEARCH_DB_PASSWORD)
                res = requests.post(**args)
                if res.status_code in (200, 201, 202):
                    if res.status_code != 200 and project == JOB_PROJECT_NAME:
                        OpenSearchDB.logger.info(
                            f"OpenSearchDB post not 200, log:{res.status_code} {res.text}"
                        )
                    return True
                else:
                    OpenSearchDB.logger.info(
                        f"OpenSearchDB post failed, will retry, error:{res.status_code} {res.text}"
                    )
            except Exception as e:
                OpenSearchDB.logger.info(
                    f"OpenSearchDB post exception, attempt {attempt + 1} error: {e}"
                )
        OpenSearchDB.logger.info(
            f"Fail to postToOpenSearchDB after {DEFAULT_RETRY_COUNT} tries: {url}, json: {json_data_dump}, last error: {getattr(res, 'text', 'N/A') if 'res' in locals() else ''}"
        )
        return False

    @staticmethod
    def queryFromOpenSearchDB(json_data, project) -> dict:
        """
        Query data from OpenSearchDB.

        :param json_data: Data to query, type dict or list.
        :param project: Name of the project.
        :return: dict, query result.
        """
        use_poc_db = "sandbox" in project
        if not OPEN_SEARCH_DB_BASE_URL:
            OpenSearchDB.logger.info("OPEN_SEARCH_DB_BASE_URL is not set")
            return None
        if not use_poc_db and project not in READ_ACCESS_PROJECT_NAME:
            OpenSearchDB.logger.info(
                f"project {project} is not in read access project list: {json.dumps(READ_ACCESS_PROJECT_NAME)}"
            )
            return None
        if not isinstance(json_data, str):
            json_data_dump = json.dumps(json_data)
        else:
            json_data_dump = json_data
        url = f"{OPEN_SEARCH_DB_BASE_URL}/opensearch/df-{project}-*/_search"
        headers = {
            "Content-Type": "application/json",
            "Accept-Charset": "UTF-8"
        }
        retry_time = DEFAULT_RETRY_COUNT
        while retry_time:
            res = requests.get(url,
                               data=json_data_dump,
                               headers=headers,
                               timeout=QUERY_TIMEOUT_SECONDS)
            if res.status_code in [200, 201, 202]:
                return res
            OpenSearchDB.logger.info(
                f"OpenSearchDB query failed, will retry, error:{res.status_code} {res.text}"
            )
            retry_time -= 1
        OpenSearchDB.logger.info(
            f"Fail to queryFromOpenSearchDB after {retry_time} retry: {url}, json: {json_data_dump}, error: {res.text}"
        )
        return None

    @staticmethod
    def queryPerfDataFromOpenSearchDB(project_name,
                                      must_clauses,
                                      size=DEFAULT_QUERY_SIZE,
                                      must_not_clauses=None):
        """
        Query perf data from OpenSearchDB using must and must_not clauses.

        :param project_name: Name of the project.
        :param must_clauses: List of must clauses for query.
        :param size: Query size.
        :param must_not_clauses: List of must_not clauses for query.
        :return: list of data dicts, empty list if no data, None on error.
        """
        if DISABLE_OPEN_SEARCH_DB_FOR_LOCAL_TEST:
            return []
        if must_clauses is None:
            must_clauses = []
        if must_not_clauses is None:
            must_not_clauses = []
        if not isinstance(must_clauses, list):
            OpenSearchDB.logger.info(
                f"Invalid must_clauses type: {type(must_clauses).__name__}")
            return None
        if not isinstance(must_not_clauses, list):
            OpenSearchDB.logger.info(
                f"Invalid must_not_clauses type: {type(must_not_clauses).__name__}"
            )
            return None

        bool_query = {"must": must_clauses}
        if must_not_clauses:
            bool_query["must_not"] = must_not_clauses

        json_data = {
            "query": {
                "bool": bool_query
            },
            "size": size,
        }

        data_list = []
        try:
            res = OpenSearchDB.queryFromOpenSearchDB(json_data, project_name)
            if res is None:
                OpenSearchDB.logger.info(
                    f"Failed to query from {project_name}, returned no response"
                )
                return None
            payload = res.json().get("hits", {}).get("hits", [])
            if len(payload) == 0:
                OpenSearchDB.logger.info(
                    f"No data found in {project_name}, returned empty list")
                return []
            for hit in payload:
                data_dict = hit.get("_source", {})
                data_dict["_id"] = hit.get("_id", "")
                if data_dict["_id"] == "":
                    OpenSearchDB.logger.info(
                        f"Failed to query from {project_name}, returned data with no _id"
                    )
                    return None
                data_list.append(data_dict)
            OpenSearchDB.logger.info(
                f"Successfully queried from {project_name}, queried {len(data_list)} entries"
            )
            return data_list
        except Exception as e:
            OpenSearchDB.logger.warning(
                f"Failed to query from {project_name}, returned error: {e}")
            return None

    @staticmethod
    def queryBuildIdFromOpenSearchDB(job_name, last_days=DEFAULT_LOOKBACK_DAYS):
        if DISABLE_OPEN_SEARCH_DB_FOR_LOCAL_TEST:
            return []
        if job_name in OpenSearchDB.query_build_id_cache:
            return OpenSearchDB.query_build_id_cache[job_name]
        json_data = {
            "size": DEFAULT_QUERY_SIZE,
            "query": {
                "range": {
                    "ts_created": {
                        "gte": OpenSearchDB._calculate_timestamp(last_days),
                    }
                }
            },
            "_source": ["ts_created", "s_job_name", "s_status", "s_build_id"],
        }
        build_ids = []
        try:
            query_res = OpenSearchDB.queryFromOpenSearchDB(
                json_data, JOB_PROJECT_NAME)
            if query_res is None:
                return []
            query_res = query_res.json()
            for job in query_res["hits"]["hits"]:
                job_info = job.get("_source", {})
                if job_name == job_info.get("s_job_name"):
                    build_ids.append(job_info.get("s_build_id"))
            OpenSearchDB.query_build_id_cache[job_name] = build_ids
            return build_ids
        except Exception as e:
            OpenSearchDB.logger.warning(
                f"Failed to query build IDs from OpenSearchDB: {e}")
            return []

    @staticmethod
    def queryPRIdsFromOpenSearchDB(repo_name, last_days=DEFAULT_LOOKBACK_DAYS):
        """
        Query existing PR IDs from OpenSearchDB for a specific repository.
        Mirrors queryBuildIdFromOpenSearchDB for PR monitoring.
        """
        if DISABLE_OPEN_SEARCH_DB_FOR_LOCAL_TEST:
            return []

        cache_key = f"pr_{repo_name}"
        if cache_key in OpenSearchDB.query_build_id_cache:
            return OpenSearchDB.query_build_id_cache[cache_key]

        json_data = {
            "size": DEFAULT_QUERY_SIZE,
            "query": {
                "bool": {
                    "must": [
                        {
                            "range": {
                                "ts_created": {
                                    "gte":
                                    OpenSearchDB._calculate_timestamp(
                                        last_days),
                                }
                            }
                        },
                        {
                            "term": {
                                "s_repo_name": repo_name
                            }
                        },
                    ]
                }
            },
            "_source": ["ts_created", "s_repo_name", "l_pr_number", "s_pr_id"],
        }

        pr_numbers = []
        try:
            query_res = OpenSearchDB.queryFromOpenSearchDB(
                json_data, PR_PROJECT_NAME)
            if query_res is None:
                return []
            query_res = query_res.json()
            for pr in query_res["hits"]["hits"]:
                pr_info = pr.get("_source", {})
                if repo_name == pr_info.get("s_repo_name"):
                    pr_number = pr_info.get("l_pr_number")
                    if pr_number and pr_number not in pr_numbers:
                        pr_numbers.append(pr_number)
            OpenSearchDB.query_build_id_cache[cache_key] = pr_numbers
            return pr_numbers
        except Exception as e:
            OpenSearchDB.logger.warning(
                f"Failed to query PR IDs from OpenSearchDB: {e}")
            return []

import argparse
import os
import sys
import xml.etree.ElementTree as ET


def parse_name(classname, name, filename):
    if "test_unittests_v2[unittest/" in name and \
       filename == "test_unittests.py":
        return name[name.find("test_unittests_v2[unittest/") + 18:-1]
    elif filename in name:
        return name[name.find('/') + 1:]
    elif filename[:-2].replace("/", ".") in classname:
        return filename + "::" + classname.split(".")[-1] + "::" + name
    else:
        return filename + "::" + name


def generate_rerun_tests_list(outdir, xml_filename, failSignaturesList):
    # Generate rerun test lists:
    # 1. Parse the test results xml file
    # 2. For failed tests:
    #    - If test duration <= 5 min: add to rerun_2.txt (will rerun 2 times)
    #    - If test duration > 5 min and <= 10 min: add to rerun_1.txt (will rerun 1 time)
    #    - If test duration > 10 min but contains fail signatures in error message: add to rerun_1.txt
    #    - If test duration > 10 min and no known failure signatures: add to rerun_0.txt (will not rerun)
    print(failSignaturesList)

    rerun_0_filename = os.path.join(outdir, 'rerun_0.txt')
    rerun_1_filename = os.path.join(outdir, 'rerun_1.txt')
    rerun_2_filename = os.path.join(outdir, 'rerun_2.txt')

    tree = ET.parse(xml_filename)
    root = tree.getroot()
    suite = root.find('testsuite')

    with open(rerun_0_filename, 'w') as rerun_0_file, \
         open(rerun_1_filename, 'w') as rerun_1_file, \
         open(rerun_2_filename, 'w') as rerun_2_file:
        for case in suite.findall('testcase'):
            if case.find('failure') is not None or \
               case.find('error') is not None:
                duration = float(case.attrib.get('time', 0))
                test_name = parse_name(case.attrib.get('classname', ''), \
                                       case.attrib.get('name', ''), \
                                       case.attrib.get('file', ''))
                if duration <= 5 * 60:
                    rerun_2_file.write(test_name + '\n')
                    print(test_name + " will rerun 2 times")
                elif duration <= 10 * 60:
                    rerun_1_file.write(test_name + '\n')
                    print(test_name + " will rerun 1 time")
                elif any(failSig.lower() in ET.tostring(
                        case, encoding='unicode').lower()
                         for failSig in failSignaturesList):
                    rerun_1_file.write(test_name + '\n')
                    print(test_name +
                          " will rerun 1 time, because of fail signature")
                else:
                    rerun_0_file.write(test_name + '\n')
                    print(test_name + " will not rerun")

    # Remove empty files
    for filename in [rerun_0_filename, rerun_1_filename, rerun_2_filename]:
        if os.path.getsize(filename) == 0:
            os.remove(filename)


def merge_junit_xmls(merged_xml_filename, xml_filenames, deduplicate=False):
    # Merge xml files into one.
    # If deduplicate is true, remove duplicate test cases.
    merged_root = ET.Element('testsuites')
    merged_suite_map = {}

    for xml_filename in xml_filenames:
        if not os.path.exists(xml_filename):
            continue

        suites = ET.parse(xml_filename).getroot()
        suite_list = suites.findall('testsuite')
        for suite in suite_list:
            suite_name = suite.attrib.get('name', '')
            if suite_name not in merged_suite_map:
                merged_suite_map[suite_name] = suite
            else:
                original_suite = merged_suite_map[suite_name]
                case_list = suite.findall('testcase')
                for case in case_list:
                    existing_case = original_suite.find(
                        f"testcase[@name='{case.attrib['name']}'][@classname='{case.attrib['classname']}']"
                    )
                    # find the duplicate case in original_suite
                    if existing_case is not None:
                        if deduplicate:
                            # remove the duplicate case in original_suite
                            original_suite.remove(existing_case)
                        else:
                            # add rerun flag to the new case for rerun report
                            case.set('isrerun', 'true')
                original_suite.extend(case_list)

    # Update suite attributes
    for suite in merged_suite_map.values():
        attribs = {'errors': 0, 'failures': 0, 'skipped': 0, 'tests': 0}
        for case in suite.findall('testcase'):
            attribs['tests'] += 1
            if case.find('failure') is not None:
                attribs['failures'] += 1
            elif case.find('error') is not None:
                attribs['errors'] += 1
            elif case.find('skipped') is not None:
                attribs['skipped'] += 1
        for key, value in attribs.items():
            suite.set(key, str(value))

        # add suite to merged_root
        merged_root.append(suite)

    if os.path.exists(merged_xml_filename):
        os.remove(merged_xml_filename)

    # Write to new file
    tree = ET.ElementTree(merged_root)
    tree.write(merged_xml_filename, encoding='utf-8', xml_declaration=True)


def escape_html(text):
    return text.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;')


def xml_to_html(xml_filename, html_filename, sort_by_name=False):
    # HTML template
    html_template = """
    <!DOCTYPE html>
    <html>
    <head>
        <title>Rerun Test Results</title>
        <style>
            body {{ font-family: Arial, sans-serif; margin: 10px; }}
            .suite-container {{
                margin-bottom: 20px;
                border: 1px solid #ddd;
                border-radius: 4px;
            }}
            .suite-header {{
                padding: 10px;
                background: #f8f9fa;
                border-bottom: 1px solid #ddd;
            }}
            .summary {{ margin-bottom: 10px; }}
            .success {{ color: #1e8e3e; }}
            .failure {{ color: #d93025; }}
            .error {{ color: #d93025; }}
            .skipped {{ color: #666666; }}
            .testcase {{
                border-left: 4px solid #ddd;
                margin: 5px 0;
                background: white;
            }}
            .testcase.success {{ border-left-color: #1e8e3e; }}
            .testcase.failure {{ border-left-color: #d93025; }}
            .testcase.error {{ border-left-color: #d93025; }}
            .testcase.skipped {{ border-left-color: #666666; }}
            .test-time {{
                color: #666;
                font-size: 12px;
                margin-left: 10px;
                float: right;
            }}
            .test-rerun-sig {{
                font-size: 12px;
                color: #666;
                margin-left: 5px;
            }}
            .test-details {{
                padding: 10px;
                background: #f5f5f5;
                border-radius: 3px;
            }}
            pre {{
                margin: 0;
                white-space: pre-wrap;
                word-wrap: break-word;
                background: #2b2b2b;
                color: #cccccc;
                padding: 10px;
                counter-reset: line;
            }}
            pre + pre {{
                border-top: none;
                padding-top: 0;
            }}
            pre span {{
                display: block;
                position: relative;
                padding-left: 4em;
            }}
            pre span:before {{
                counter-increment: line;
                content: counter(line);
                position: absolute;
                left: 0;
                width: 3em;
                text-align: right;
                color: #666;
                padding-right: 1em;
            }}
            details summary {{
                cursor: pointer;
                outline: none;
            }}
            details[open] summary {{
                margin-bottom: 10px;
            }}
        </style>
    </head>
    <body>
        <h2>Rerun Test Results</h2>
        {test_suites}
    </body>
    </html>
    """

    # Parse XML
    tree = ET.parse(xml_filename)
    root = tree.getroot()
    suite_list = root.findall('testsuite')

    all_suites_html = []

    for suite in suite_list:
        tests_count = int(suite.attrib.get('tests', 0))
        failed_tests_count = int(suite.attrib.get('failures', 0)) + \
                         int(suite.attrib.get('errors', 0))
        skipped_tests_count = int(suite.attrib.get('skipped', 0))
        passed_tests_count = tests_count - failed_tests_count - skipped_tests_count

        # Generate summary for the suite
        summary = f"""
            <div class="suite-header">
                <h3>Stage: {suite.attrib.get('name', '')}</h3>
                <p>Tests: {tests_count} |
                   <span class="failure">Failed: {failed_tests_count}</span> |
                   <span class="skipped">Skipped: {skipped_tests_count}</span> |
                   <span class="success">Passed: {passed_tests_count}</span>
                </p>
            </div>
        """

        # Generate test case details for the suite
        test_cases_html = []
        all_test_cases = []

        for testcase in suite.findall('testcase'):
            status = "success"
            if testcase.find('failure') is not None:
                status = "failure"
            elif testcase.find('error') is not None:
                status = "error"
            elif testcase.find('skipped') is not None:
                status = "skipped"
            all_test_cases.append((status, testcase))

        if sort_by_name:
            all_test_cases.sort(key=lambda x: x[1].attrib.get('name', '') + \
                                x[1].attrib.get('classname', ''))
        else:
            # Sort test cases: failure/error first, then skipped, then success
            status_order = {
                "failure": 0,
                "error": 1,
                "skipped": 2,
                "success": 3
            }
            all_test_cases.sort(key=lambda x: status_order[x[0]])

        # Generate HTML for sorted test cases
        for status, testcase in all_test_cases:
            test_rerun_sig = '[RERUN]' if testcase.attrib.get(
                'isrerun', '') == 'true' else ''
            test_name = f"{testcase.attrib.get('name', '')} - {testcase.attrib.get('classname', '')}"
            test_time = f"{float(testcase.attrib.get('time', 0)):.3f}s"

            if status == "failure":
                failure = testcase.find('failure')
                system_out = testcase.find('system-out')
                system_err = testcase.find('system-err')
                details = f"""
                    <details class="test-details">
                        <summary>{test_name}<span class="test-rerun-sig">{test_rerun_sig}</span><span class="test-time">{test_time}</span></summary>
                        <pre>{''.join(f'<span>{escape_html(line)}</span>' for line in failure.get('message', '').splitlines(True))}</pre>
                        <pre>{''.join(f'<span>{escape_html(line)}</span>' for line in (failure.text or '').splitlines(True))}</pre>
                        <pre>{''.join(f'<span>{escape_html(line)}</span>' for line in (system_out.text or '').splitlines(True))}</pre>
                        <pre>{''.join(f'<span>{escape_html(line)}</span>' for line in (system_err.text or '').splitlines(True))}</pre>
                    </details>
                """
            elif status == "error":
                error = testcase.find('error')
                system_out = testcase.find('system-out')
                system_err = testcase.find('system-err')
                details = f"""
                    <details class="test-details">
                        <summary>{test_name}<span class="test-rerun-sig">{test_rerun_sig}</span><span class="test-time">{test_time}</span></summary>
                        <pre>{''.join(f'<span>{escape_html(line)}</span>' for line in error.get('message', '').splitlines(True))}</pre>
                        <pre>{''.join(f'<span>{escape_html(line)}</span>' for line in (error.text or '').splitlines(True))}</pre>
                        <pre>{''.join(f'<span>{escape_html(line)}</span>' for line in (system_out.text or '').splitlines(True))}</pre>
                        <pre>{''.join(f'<span>{escape_html(line)}</span>' for line in (system_err.text or '').splitlines(True))}</pre>
                    </details>
                """
            elif status == "skipped":
                skipped_message = testcase.find('skipped').attrib.get(
                    'message', '')
                details = f"""
                    <details class="test-details">
                        <summary>{test_name}<span class="test-rerun-sig">{test_rerun_sig}</span><span class="test-time">{test_time}</span></summary>
                        <pre>{''.join(f'<span>{escape_html(line)}</span>' for line in skipped_message.splitlines(True))}</pre>
                    </details>
                """
            else:
                system_out = testcase.find('system-out')
                system_err = testcase.find('system-err')
                details = f"""
                    <details class="test-details">
                        <summary>{test_name}<span class="test-rerun-sig">{test_rerun_sig}</span><span class="test-time">{test_time}</span></summary>
                        <pre>{''.join(f'<span>{escape_html(line)}</span>' for line in (system_out.text or '').splitlines(True))}</pre>
                        <pre>{''.join(f'<span>{escape_html(line)}</span>' for line in (system_err.text or '').splitlines(True))}</pre>
                    </details>
                """

            test_case_html = f"""
                <div class="testcase {status}">
                    {details}
                </div>
            """
            test_cases_html.append(test_case_html)

        # Combine summary and test cases for this suite
        suite_html = f"""
            <div class="suite-container">
                {summary}
                <div class="test-cases">
                    {' '.join(test_cases_html)}
                </div>
            </div>
        """
        all_suites_html.append(suite_html)

    # Generate complete HTML
    html_content = html_template.format(test_suites='\n'.join(all_suites_html))

    # Write to file
    with open(html_filename, 'w', encoding='utf-8') as f:
        f.write(html_content)


def filter_failed_tests(xml_filename, output_filename):
    # Filter failed tests from the xml file
    filtered_root = ET.Element('testsuites')

    root = ET.parse(xml_filename).getroot()
    suite_list = root.findall('testsuite')
    for suite in suite_list:
        filtered_suite = ET.Element('testsuite')
        # Copy attributes one by one
        for key, value in suite.attrib.items():
            filtered_suite.set(key, value)
        filtered_suite.set(
            'tests',
            str(
                int(suite.attrib.get('failures', '0')) +
                int(suite.attrib.get('errors', '0'))))
        filtered_suite.set('skipped', '0')

        filtered_cases = []
        for case in suite.findall('testcase'):
            if case.find('failure') is not None or \
               case.find('error') is not None:
                filtered_cases.append(case)

        filtered_suite.extend(filtered_cases)
        filtered_root.append(filtered_suite)

    tree = ET.ElementTree(filtered_root)
    tree.write(output_filename, encoding='utf-8', xml_declaration=True)


def generate_rerun_report(output_filename, input_filenames):
    # Merge the input xml files (filter failed tests for results.xml and results_isolated_*.xml)
    # and generate the rerun report html file.
    new_filename_list = []
    for input_filename in input_filenames:
        new_filename = input_filename
        if "/results.xml" in input_filename:
            new_filename = input_filename.replace("results.xml",
                                                  "failed_results.xml")
            filter_failed_tests(input_filename, new_filename)
        elif "/results_isolated_" in input_filename and input_filename.endswith(
                ".xml"):
            # Handle isolation test result files: results_isolated_*.xml -> failed_results_isolated_*.xml
            new_filename = input_filename.replace("results_isolated_",
                                                  "failed_results_isolated_")
            filter_failed_tests(input_filename, new_filename)
        new_filename_list.append(new_filename)

    print(new_filename_list)
    merge_junit_xmls(output_filename, new_filename_list)
    xml_to_html(output_filename,
                output_filename.replace(".xml", ".html"),
                sort_by_name=True)


