"""Generate a pre-merge HTML report with inline SVG performance charts.

Reads perf_data.yaml files produced by test stages, queries OpenSearch for
historical data and baselines, then generates an HTML report visualizing
key throughput metrics with history, new data, baseline, and threshold lines
for regression comparison.
"""

import argparse
import os
from html import escape as escape_html

import yaml

# Set OPEN_SEARCH_DB_BASE_URL before importing perf_utils, because
# open_search_db captures the env var at module-import time.
if not os.environ.get("OPEN_SEARCH_DB_BASE_URL"):
    os.environ["OPEN_SEARCH_DB_BASE_URL"] = "http://gpuwa.nvidia.com"

from perf_utils import (
    CHART_METRICS,
    METRIC_LABELS,
    _extract_points,
    _generate_svg_chart,
    _get_threshold_for_metric,
    _ts_to_date,
    get_history_data,
)

# ---------------------------------------------------------------------------
# Data gathering
# ---------------------------------------------------------------------------


def load_perf_data(input_files):
    """Read comma-separated perf_data.yaml paths and return a flat list of new_data dicts."""
    yaml_files = [f.strip() for f in input_files.split(",") if f.strip()]
    all_new_data = []
    load_failures = 0
    for yaml_file in yaml_files:
        try:
            with open(yaml_file, "r", encoding="utf-8") as f:
                content = yaml.safe_load(f)
            if content is None or not isinstance(content, list):
                continue
            for e in content:
                if not isinstance(e, dict):
                    continue
                nd = e.get("new_data")
                if isinstance(nd, dict) and "s_test_case_name" in nd:
                    all_new_data.append(nd)
        except (OSError, yaml.YAMLError, UnicodeDecodeError) as exc:
            load_failures += 1
            print(f"Warning: Failed to load {yaml_file}: {exc}")
    if yaml_files and not all_new_data and load_failures == len(yaml_files):
        raise RuntimeError("Failed to load any perf data YAML inputs; cannot generate report.")
    return all_new_data


# ---------------------------------------------------------------------------
# History data query
# ---------------------------------------------------------------------------


def get_pre_merge_history_data(new_data_list):
    """Query OpenSearch for history data matching test cases in *new_data_list*.

    Uses :func:`perf_utils.get_history_data` to fetch post-merge history
    (both baseline and non-baseline), then filters to only the
    (s_test_case_name, s_gpu_type) pairs present in *new_data_list*.

    Returns:
        dict mapping (test_case, gpu_type) -> {
            "history_data": [...],
            "baseline_data": [...],
        }
        or empty dict on failure / no matches.
    """
    if not new_data_list:
        return {}

    # Determine which test case keys are present in new data
    needed_keys = set()
    for nd in new_data_list:
        key = (nd.get("s_test_case_name", ""), nd.get("s_gpu_type", ""))
        needed_keys.add(key)

    grouped = get_history_data(
        extra_must_clauses=[
            {"term": {"b_is_post_merge": True}},
            {"term": {"s_branch": "main"}},
        ]
    )

    if grouped is None:
        print("Warning: Failed to query history data from OpenSearch")
        return {}

    # Filter to only the test cases we have new data for
    filtered = {}
    for key, bucket in grouped.items():
        if key in needed_keys:
            filtered[key] = bucket

    return filtered


# ---------------------------------------------------------------------------
# HTML report generation
# ---------------------------------------------------------------------------


def _extract_simple_points(data_list, metric):
    """Extract (datetime, float_value) pairs from a list of data dicts."""
    points = []
    for d in data_list:
        ts = d.get("ts_created") or d.get("@timestamp")
        val = d.get(metric)
        if ts is not None and val is not None:
            try:
                points.append((_ts_to_date(ts), float(val)))
            except (ValueError, TypeError):
                pass
    points.sort(key=lambda p: p[0])
    return points


def generate_pre_merge_html(new_data_list, history_grouped, output_file):
    """Generate HTML report visualizing new data against history + baseline.

    For each (test_case, gpu_type) present in *new_data_list*, renders 4
    charts (one per key metric) showing history line, new data points,
    baseline line, and threshold line for regression comparison.
    """
    # Group new data by (test_case, gpu_type)
    new_groups = {}
    for nd in new_data_list:
        key = (nd.get("s_test_case_name", ""), nd.get("s_gpu_type", ""))
        new_groups.setdefault(key, []).append(nd)

    sections_html = []
    for (test_case, gpu_type), new_data_entries in sorted(new_groups.items()):
        bucket = history_grouped.get((test_case, gpu_type), {})
        history_data = bucket.get("history_data", [])
        baseline_data_list = bucket.get("baseline_data", [])

        charts = []
        for metric in CHART_METRICS:
            label = METRIC_LABELS.get(metric, metric)

            # History points (blue line) — use 3-tuple version from perf_utils
            hist_pts = _extract_points(history_data, metric)

            # New data points (red dots)
            new_pts = _extract_simple_points(new_data_entries, metric)

            # Baseline value from the latest baseline entry
            baseline_value = None
            if baseline_data_list:
                latest_bl = baseline_data_list[-1]
                bl_val = latest_bl.get(metric)
                if bl_val is not None:
                    baseline_value = float(bl_val)

            # Threshold line value
            threshold_line_value = None
            if baseline_value is not None:
                threshold = _get_threshold_for_metric(baseline_data_list, metric)
                threshold_line_value = baseline_value * (1 - threshold)

            charts.append(
                _generate_svg_chart(
                    hist_pts,
                    metric,
                    label,
                    new_points=new_pts,
                    baseline_value=baseline_value,
                    threshold_line_value=threshold_line_value,
                )
            )

        header = escape_html(f"{test_case}  [{gpu_type}]")
        section = f"""
        <details class="test-section" open>
            <summary><strong>{header}</strong></summary>
            <div class="charts-grid">
                {"".join(charts)}
            </div>
        </details>
        """
        sections_html.append(section)

    total_new = len(new_data_list)
    html = f"""<!DOCTYPE html>
<html>
<head>
    <meta charset="utf-8">
    <title>Perf Sanity Pre-Merge Results</title>
    <style>
        body {{ font-family: Arial, sans-serif; margin: 20px; background: #fafafa; }}
        h2 {{ color: #333; }}
        .test-section {{
            margin-bottom: 15px;
            border: 1px solid #ddd;
            border-radius: 6px;
            background: #fff;
            padding: 10px 15px;
        }}
        .test-section summary {{
            cursor: pointer;
            font-size: 14px;
            padding: 6px 0;
        }}
        .charts-grid {{
            display: flex;
            flex-wrap: wrap;
            gap: 10px;
            margin-top: 10px;
        }}
        .summary-info {{ color: #666; margin-bottom: 15px; }}
    </style>
</head>
<body>
    <h2>Perf Sanity Pre-Merge Results</h2>
    <p class="summary-info">{len(new_groups)} test case(s) &middot; {total_new} new data point(s)</p>
    {"".join(sections_html)}
</body>
</html>
"""
    with open(output_file, "w", encoding="utf-8") as f:
        f.write(html)

    print(f"Generated pre-merge perf report with {len(new_groups)} test cases: {output_file}")


# ---------------------------------------------------------------------------
# CLI
# ---------------------------------------------------------------------------


def main():
    parser = argparse.ArgumentParser(
        description="Generate a pre-merge HTML report with historical "
        "performance charts, baseline, and threshold lines."
    )
    parser.add_argument(
        "--input-files",
        type=str,
        required=True,
        help="Comma-separated list of perf_data.yaml paths",
    )
    parser.add_argument("--output-file", type=str, required=True, help="Output HTML file path")
    args = parser.parse_args()

    new_data_list = load_perf_data(args.input_files)
    history_grouped = get_pre_merge_history_data(new_data_list)
    generate_pre_merge_html(new_data_list, history_grouped, args.output_file)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3

import argparse
import json
import re
import sys
import time
from datetime import datetime, timezone

from slack_sdk import WebClient
from slack_sdk.errors import SlackApiError

sys.path.insert(0, sys.path[0] + "/..")
from open_search_db import OpenSearchDB

QUERY_LOOKBACK_DAYS = 90
LOOKBACK_JOBS = 30
MAX_QUERY_SIZE = 3000
MAX_TEST_CASES_PER_MSG = 4
POST_SLACK_MSG_RETRY_TIMES = 5

# Comparison operators (order matters: >= before >, <= before <, != before =)
COMPARISON_OPERATORS = [">=", "<=", "!=", ">", "<", "="]
COMPARISON_ALLOWED_PREFIXES = ("d_", "l_")
COMPARISON_ALLOWED_FIELDS = ("ts_created",)


def _timestamp_to_date(ts):
    """Convert millisecond timestamp to YYYY/MM/DD format."""
    if ts == "N/A" or ts is None:
        return "N/A"
    try:
        ts_int = int(ts)
        # Convert milliseconds to seconds
        dt = datetime.fromtimestamp(ts_int / 1000)
        return dt.strftime("%Y/%m/%d")
    except (ValueError, TypeError, OSError):
        return str(ts)


def _parse_date_string(date_str):
    """Convert date string like 'Feb 18, 2026 @ 22:32:02.960' to millisecond timestamp.

    All date strings are interpreted as UTC to ensure consistent timestamps
    across different environments/timezones.
    """
    date_str = date_str.strip()
    # Try format: "Feb 18, 2026 @ 22:32:02.960"
    try:
        dt = datetime.strptime(date_str, "%b %d, %Y @ %H:%M:%S.%f")
        dt = dt.replace(tzinfo=timezone.utc)
        return int(dt.timestamp() * 1000)
    except ValueError:
        pass
    # Try format: "Feb 18, 2026 @ 22:32:02"
    try:
        dt = datetime.strptime(date_str, "%b %d, %Y @ %H:%M:%S")
        dt = dt.replace(tzinfo=timezone.utc)
        return int(dt.timestamp() * 1000)
    except ValueError:
        pass
    # Try format: "2026/02/18"
    try:
        dt = datetime.strptime(date_str, "%Y/%m/%d")
        dt = dt.replace(tzinfo=timezone.utc)
        return int(dt.timestamp() * 1000)
    except ValueError:
        pass
    raise ValueError(f"Unable to parse date string: {date_str}")


def _can_use_comparison_operator(field_name):
    """Check if a field can use comparison operators (>, <, >=, <=)."""
    if field_name in COMPARISON_ALLOWED_FIELDS:
        return True
    if field_name.startswith(COMPARISON_ALLOWED_PREFIXES):
        return True
    return False


def _parse_value(value):
    value = value.strip()
    if len(value) >= 2 and ((value[0] == value[-1]) and value[0] in ("'", '"')):
        return value[1:-1]
    lower = value.lower()
    if lower == "true":
        return True
    if lower == "false":
        return False
    if re.fullmatch(r"-?\d+", value):
        return int(value)
    if re.fullmatch(r"-?\d+\.\d+", value):
        return float(value)
    return value


def _split_and_clauses(text):
    return [
        part.strip() for part in re.split(r"\s+AND\s+", text, flags=re.IGNORECASE) if part.strip()
    ]


def _parse_assignments(text):
    clauses = _split_and_clauses(text)
    if not clauses:
        return None, "No fields provided"
    result = {}
    for clause in clauses:
        if "=" not in clause:
            return None, f"Invalid clause (missing '='): {clause}"
        key, value = clause.split("=", 1)
        key = key.strip()
        if not key:
            return None, f"Invalid clause (empty field name): {clause}"
        result[key] = _parse_value(value)
    return result, None


def _parse_where_clauses(text):
    """Parse WHERE clauses supporting =, >, <, >=, <= operators.

    Returns a list of tuples: (field_name, operator, value)
    Only d_*, l_*, and ts_created fields can use comparison operators.
    """
    clauses = _split_and_clauses(text)
    if not clauses:
        return None, "No fields provided"

    result = []
    for clause in clauses:
        # Match: field_name <operator> value
        # Using regex to find operator right after field name, avoiding false matches in values
        m = re.match(r"^\s*(\w+)\s*(>=|<=|!=|>|<|=)\s*(.*)", clause)
        if not m:
            return None, f"Invalid clause (missing operator): {clause}"

        key = m.group(1).strip()
        found_op = m.group(2)
        value = _parse_value(m.group(3))

        if not key:
            return None, f"Invalid clause (empty field name): {clause}"

        # Check if comparison operator is allowed for this field
        # != is allowed for all fields, but >, <, >=, <= are restricted
        if found_op not in ("=", "!=") and not _can_use_comparison_operator(key):
            return None, (
                f"Comparison operator '{found_op}' not allowed for field '{key}'. "
                f"Only fields starting with 'd_', 'l_', or field 'ts_created' can use >, <, >=, <= operators."
            )

        # Convert date string to timestamp for ts_created
        if key == "ts_created" and isinstance(value, str):
            try:
                value = _parse_date_string(value)
            except ValueError as e:
                return None, str(e)

        result.append((key, found_op, value))

    return result, None


def _build_opensearch_clause(field, operator, value):
    """Build OpenSearch query clause from field, operator, and value.

    Returns a tuple (clause_type, clause) where clause_type is "must" or "must_not".
    """
    if operator == "=":
        return ("must", {"term": {field: value}})

    if operator == "!=":
        return ("must_not", {"term": {field: value}})

    op_map = {
        ">": "gt",
        "<": "lt",
        ">=": "gte",
        "<=": "lte",
    }
    return ("must", {"range": {field: {op_map[operator]: value}}})


def parse_update_operation(operation):
    match = re.match(
        r"^\s*UPDATE\s+SET\s+(.+?)(?:\s+WHERE\s+(.+))?\s*$", operation, flags=re.IGNORECASE
    )
    if not match:
        return None, None, "Invalid UPDATE operation format"
    set_text = match.group(1).strip()
    where_text = match.group(2).strip() if match.group(2) else ""
    set_values, error = _parse_assignments(set_text)
    if error:
        return None, None, f"Invalid SET clause: {error}"
    where_clauses = []
    if match.group(2) is not None:
        if not where_text:
            return None, None, "Invalid WHERE clause: empty scope"
        where_clauses, error = _parse_where_clauses(where_text)
        if error:
            return None, None, f"Invalid WHERE clause: {error}"
    return set_values, where_clauses, None


def update_perf_data_fields(data_list, set_values):
    updated_list = []
    for data in data_list:
        updated_data = data.copy()
        for key, value in set_values.items():
            updated_data[key] = value
        updated_list.append(updated_data)
    return updated_list


def post_perf_data(data_list, project_name):
    if not data_list:
        print(f"No data to post to {project_name}")
        return False
    try:
        print(f"Ready to post {len(data_list)} data to {project_name}")
        return OpenSearchDB.postToOpenSearchDB(data_list, project_name)
    except Exception as e:
        print(f"Failed to post data to {project_name}, error: {e}")
        return False


def get_regression_dict(data_list, query_job_number, lookback_job_number=LOOKBACK_JOBS):
    """Returns a dict with job_id as key and list of regression tuples as value.

    Each tuple is (test_case_name, gpu_type, runtime, history_regression_job_ids, data).
    Only returns the latest query_job_number jobs.
    """
    if data_list is None or len(data_list) == 0:
        return {}

    # Group data by job_id
    job_test_dict = {}
    for data in data_list:
        raw_job_id = data.get("s_job_id", "")
        if raw_job_id == "":
            continue
        try:
            job_id = int(raw_job_id)
        except (TypeError, ValueError):
            continue
        job_test_dict.setdefault(job_id, []).append(data)

    if not job_test_dict:
        return {}

    # Sort job_ids (descending: latest -> oldest)
    sorted_job_id_list = sorted(job_test_dict.keys(), reverse=True)

    # Build (test_case_name, gpu_type, runtime) -> job_ids dict
    test_job_dict = {}
    for job_id, data_list in job_test_dict.items():
        for data in data_list:
            test_case_name = data.get("s_test_case_name") or ""
            gpu_type = data.get("s_gpu_type") or ""
            runtime = data.get("s_runtime") or ""
            if not test_case_name or not gpu_type or not runtime:
                continue
            key = (test_case_name, gpu_type, runtime)
            test_job_dict.setdefault(key, set()).add(job_id)

    # Sort job ids for each test case (descending: latest -> oldest)
    for key, job_id_set in list(test_job_dict.items()):
        test_job_dict[key] = sorted(job_id_set, reverse=True)

    # Only keep the latest query_job_number jobs in the result
    latest_job_ids = sorted_job_id_list[:query_job_number]

    regression_dict = {}
    for job_id in latest_job_ids:
        entries = []
        for data in job_test_dict.get(job_id, []):
            test_case_name = data.get("s_test_case_name") or ""
            gpu_type = data.get("s_gpu_type") or ""
            runtime = data.get("s_runtime") or ""
            if not test_case_name or not gpu_type or not runtime:
                continue
            key = (test_case_name, gpu_type, runtime)
            history_ids = test_job_dict.get(key, [])
            lower_bound = job_id - lookback_job_number + 1
            history_regression_job_ids = [
                jid for jid in history_ids if lower_bound <= jid <= job_id
            ]
            entries.append((test_case_name, gpu_type, runtime, history_regression_job_ids, data))
        regression_dict[job_id] = entries

    return regression_dict


def split_regression_message(regression_dict):
    """Process regression data into message chunks.

    Returns a list of messages, each containing at most MAX_TEST_CASES_PER_MSG test cases.
    """
    if not regression_dict:
        return []

    # Flatten all test cases into a list with
    # (job_id, idx, test_case_name, gpu_type, runtime, history_regression_job_ids, data) tuples
    all_test_cases = []
    for job_id, data_list in regression_dict.items():
        sorted_data_list = sorted(data_list, key=lambda x: x[0])
        for idx, (test_case_name, gpu_type, runtime, history_regression_job_ids, data) in enumerate(
            sorted_data_list, start=1
        ):
            all_test_cases.append(
                (job_id, idx, test_case_name, gpu_type, runtime, history_regression_job_ids, data)
            )

    # Split into chunks of MAX_TEST_CASES_PER_MSG
    chunks = []
    for i in range(0, len(all_test_cases), MAX_TEST_CASES_PER_MSG):
        chunks.append(all_test_cases[i : i + MAX_TEST_CASES_PER_MSG])

    # Build messages for each chunk
    messages = []
    for chunk in chunks:
        msg_parts = []
        current_job_id = None
        for (
            job_id,
            idx,
            test_case_name,
            gpu_type,
            runtime,
            history_regression_job_ids,
            data,
        ) in chunk:
            # Add job header when switching to a new job_id
            if job_id != current_job_id:
                if msg_parts:
                    msg_parts.append("\n")
                job_header = f"*LLM/main/L0_PostMerge/{job_id}:*\n"
                msg_parts.append(job_header)
                current_job_id = job_id

            regression_info = data.get("s_regression_info", "N/A")
            history_text = (
                ", ".join(str(jid) for jid in history_regression_job_ids)
                if history_regression_job_ids
                else "N/A"
            )
            msg_parts.append(f"*REGRESSION TEST CASE {idx}: {test_case_name}*\n")
            msg_parts.append(f"*GPU: {gpu_type} Mode: {runtime}*\n")
            msg_parts.append(f"*History Regression Post-Merge Job IDs: {history_text}*\n")

            # Parse regression_info to extract baseline info and metrics
            baseline_date = "N/A"
            baseline_branch = "N/A"
            baseline_commit = "N/A"
            for part in regression_info.split(","):
                part = part.strip()
                if "baseline_date:" in part:
                    baseline_date = _timestamp_to_date(part.split(":", 1)[-1].strip())
                elif "baseline_branch:" in part:
                    baseline_branch = part.split(":", 1)[-1].strip()
                elif "baseline_commit:" in part:
                    baseline_commit = part.split(":", 1)[-1].strip()

            # Get regression branch and commit from data
            regression_date = _timestamp_to_date(data.get("ts_created", "N/A"))
            regression_branch = data.get("s_branch", "N/A")
            regression_commit = data.get("s_commit", "N/A")

            msg_parts.append(
                f"*Baseline date, branch and commit: "
                f"{baseline_date} {baseline_branch} {baseline_commit}*\n"
            )
            msg_parts.append(
                f"*Regression date, branch and commit: "
                f"{regression_date} {regression_branch} {regression_commit}*\n"
            )

            for part in regression_info.split(","):
                part = part.strip()
                if part and "baseline_" not in part:
                    msg_parts.append(f"  {part}\n")

        msg = "".join(msg_parts).strip()
        messages.append(msg)

    return messages


def send_regression_message(messages, channel_id, bot_token):
    """Send regression messages to Slack channel(s).

    channel_id can be a single ID or multiple IDs separated by commas.
    """
    if not messages:
        print("No regression data to send")
        return

    if channel_id and bot_token:
        channel_ids = [cid.strip() for cid in channel_id.split(",") if cid.strip()]
        for cid in channel_ids:
            for msg in messages:
                send_message(msg, cid, bot_token)
    else:
        print("Slack channel_id or bot_token not provided, printing message:")
        for i, msg in enumerate(messages, start=1):
            print(f"--- Message {i} ---")
            print(msg)


def send_message(msg, channel_id, bot_token):
    """Send message to Slack channel using slack_sdk."""
    client = WebClient(token=bot_token)

    attachments = [
        {
            "title": "Perf Sanity Regression Report",
            "color": "#ff0000",
            "text": msg,
        }
    ]

    for attempt in range(1, POST_SLACK_MSG_RETRY_TIMES + 1):
        try:
            result = client.chat_postMessage(
                channel=channel_id,
                attachments=attachments,
            )
            assert result["ok"] is True, json.dumps(result.data)
            print(f"Message sent successfully to channel {channel_id}")
            return
        except SlackApiError as e:
            print(
                f"Attempt {attempt}/{POST_SLACK_MSG_RETRY_TIMES}: Error sending message to Slack: {e}"
            )
        except Exception as e:
            print(f"Attempt {attempt}/{POST_SLACK_MSG_RETRY_TIMES}: Unexpected error: {e}")

        if attempt < POST_SLACK_MSG_RETRY_TIMES:
            time.sleep(1)

    print(
        f"Failed to send message to channel {channel_id} after {POST_SLACK_MSG_RETRY_TIMES} attempts"
    )


def main():
    parser = argparse.ArgumentParser(description="Perf Sanity Triage Script")
    parser.add_argument("--project_name", type=str, required=True, help="OpenSearch project name")
    parser.add_argument("--operation", type=str, required=True, help="Operation to perform")
    parser.add_argument(
        "--channel_id",
        type=str,
        default="",
        help="Slack channel ID(s), comma-separated for multiple channels",
    )
    parser.add_argument("--bot_token", type=str, default="", help="Slack bot token")
    parser.add_argument(
        "--query_job_number", type=int, default=1, help="Number of latest jobs to query"
    )

    args = parser.parse_args()

    print(f"Project Name: {args.project_name}")
    print(f"Operation: {args.operation}")
    print(f"Channel ID: {args.channel_id}")
    print(f"Bot Token: {'***' if args.bot_token else 'Not provided'}")
    print(f"Query Job Number: {args.query_job_number}")

    if args.operation == "SLACK BOT SENDS MESSAGE":
        last_days = QUERY_LOOKBACK_DAYS
        must_clauses = [
            {"term": {"b_is_valid": True}},
            {"term": {"b_is_post_merge": True}},
            {"term": {"b_is_regression": True}},
            {"term": {"b_is_baseline": False}},
            {
                "range": {
                    "ts_created": {
                        "gte": int(time.time() - 24 * 3600 * last_days)
                        // (24 * 3600)
                        * 24
                        * 3600
                        * 1000,
                    }
                }
            },
        ]
        data_list = OpenSearchDB.queryPerfDataFromOpenSearchDB(
            args.project_name, must_clauses, size=MAX_QUERY_SIZE
        )
        if data_list is None:
            print("Failed to query regression data")
            return

        regression_dict = get_regression_dict(data_list, args.query_job_number)
        messages = split_regression_message(regression_dict)
        send_regression_message(messages, args.channel_id, args.bot_token)
    elif args.operation.strip().upper().startswith("UPDATE"):
        set_values, where_clauses, error = parse_update_operation(args.operation)
        if error:
            print(error)
            return

        must_clauses = []
        must_not_clauses = []
        for field, operator, value in where_clauses:
            clause_type, clause = _build_opensearch_clause(field, operator, value)
            if clause_type == "must":
                must_clauses.append(clause)
            else:
                must_not_clauses.append(clause)

        data_list = OpenSearchDB.queryPerfDataFromOpenSearchDB(
            args.project_name, must_clauses, size=MAX_QUERY_SIZE, must_not_clauses=must_not_clauses
        )
        if data_list is None:
            print("Failed to query data for update")
            return
        if len(data_list) == 0:
            print("No data matched the update scope")
            return

        updated_data_list = update_perf_data_fields(data_list, set_values)
        if not post_perf_data(updated_data_list, args.project_name):
            print("Failed to post updated data")
            return
        print(f"Updated {len(updated_data_list)} entries successfully")
    else:
        print(f"Unknown operation: {args.operation}")


if __name__ == "__main__":
    main()
